//! Roc Platform ABI for Zig
//!
//! This file defines the Zig interface for hosted functions in a Roc platform.
//! It is automatically generated by the Roc glue generator.

/// RocStr - Roc string type
///
/// A 24-byte structure representing a string. Small strings (up to 23 bytes
/// on 64-bit systems) are stored inline. Larger strings store a pointer to
/// heap-allocated data.
pub const RocStr = extern struct {
    bytes: ?[*]u8,
    len: usize,
    capacity: usize,

    comptime {
        if (@sizeOf(RocStr) != 24) @compileError("RocStr must be 24 bytes");
        if (@alignOf(RocStr) != 8) @compileError("RocStr must be 8-byte aligned");
    }
};

/// RocList - Roc list type
///
/// A 24-byte structure representing a list. Similar to RocStr, but for
/// arbitrary element types.
pub const RocList = extern struct {
    elements: ?*anyopaque,
    len: usize,
    capacity: usize,

    comptime {
        if (@sizeOf(RocList) != 24) @compileError("RocList must be 24 bytes");
        if (@alignOf(RocList) != 8) @compileError("RocList must be 8-byte aligned");
    }
};

/// RocOps - opaque type for Roc runtime operations
/// Contains function pointers for allocation, deallocation, etc.
pub const RocOps = opaque {};

/// HostedFn - Function pointer type for hosted functions
///
/// All hosted functions follow this signature:
///   - ops: pointer to Roc runtime operations
///   - args: pointer to function-specific arguments struct (or null if no args)
///   - ret: pointer to return value storage (or null if void return)
pub const HostedFn = *const fn (ops: *RocOps, args: ?*anyopaque, ret: ?*anyopaque) void;

pub const hosted_idx_builder_print_value: usize = 0;
pub const hosted_idx_host_get_greeting: usize = 1;
pub const hosted_idx_stderr_line: usize = 2;
pub const hosted_idx_stdin_line: usize = 3;
pub const hosted_idx_stdout_line: usize = 4;

/// Arguments for Builder.print_value!
pub const BuilderPrintValueArgs = extern struct {
    arg0: ?*anyopaque,
};

/// Arguments for Host.get_greeting!
pub const HostGetGreetingArgs = extern struct {
    arg0: ?*anyopaque,
};

/// Arguments for Stderr.line!
pub const StderrLineArgs = extern struct {
    arg0: RocStr,
};

/// Arguments for Stdout.line!
pub const StdoutLineArgs = extern struct {
    arg0: RocStr,
};

/// Platform - typed interface to Roc hosted functions
///
/// Contains function pointers for each hosted function, plus typed
/// convenience methods that handle argument packing and return value unpacking.
pub const Platform = struct {
    builder_print_value: HostedFn,
    host_get_greeting: HostedFn,
    stderr_line: HostedFn,
    stdin_line: HostedFn,
    stdout_line: HostedFn,

    pub fn builderPrintValue(self: Platform, ops: *RocOps, arg0: ?*anyopaque) void {
        var args = BuilderPrintValueArgs{ .arg0 = arg0, };
        self.builder_print_value(ops, @ptrCast(&args), null);
    }

    pub fn hostGetGreeting(self: Platform, ops: *RocOps, arg0: ?*anyopaque) RocStr {
        var args = HostGetGreetingArgs{ .arg0 = arg0, };
        var ret: RocStr = undefined;
        self.host_get_greeting(ops, @ptrCast(&args), @ptrCast(&ret));
        return ret;
    }

    pub fn stderrLine(self: Platform, ops: *RocOps, arg0: RocStr) void {
        var args = StderrLineArgs{ .arg0 = arg0, };
        self.stderr_line(ops, @ptrCast(&args), null);
    }

    pub fn stdinLine(self: Platform, ops: *RocOps) RocStr {
        var ret: RocStr = undefined;
        self.stdin_line(ops, null, @ptrCast(&ret));
        return ret;
    }

    pub fn stdoutLine(self: Platform, ops: *RocOps, arg0: RocStr) void {
        var args = StdoutLineArgs{ .arg0 = arg0, };
        self.stdout_line(ops, @ptrCast(&args), null);
    }
};
